tests:
def test_required_pass():
    r = Required().validate('hello')
    assert r.valid is True

def test_required_fail_none():
    r = Required().validate(None)
    assert r.valid is False

def test_required_fail_empty():
    r = Required().validate('')
    assert r.valid is False

def test_min_length():
    assert MinLength(3).validate('abc').valid is True
    assert MinLength(3).validate('ab').valid is False

def test_max_length():
    assert MaxLength(3).validate('ab').valid is True
    assert MaxLength(3).validate('abcd').valid is False

def test_regex():
    assert Regex(r'^\d+$').validate('12345').valid is True
    assert Regex(r'^\d+$').validate('abc').valid is False
